import{_ as a,o as n,c as t,a3 as i}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Workspace provisioning","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Workspace provisioning | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/tenant-provisioning"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Workspace provisioning | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/tenant-provisioning"}]]},"headers":[],"relativePath":"developer-guide/tenant-provisioning.md","filePath":"developer-guide/tenant-provisioning.md","lastUpdated":1784475221000}'),o={name:"developer-guide/tenant-provisioning.md"};function s(l,e,r,d,p,c){return n(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="workspace-provisioning" tabindex="-1">Workspace provisioning <a class="header-anchor" href="#workspace-provisioning" aria-label="Permalink to &quot;Workspace provisioning&quot;">​</a></h1><p>Provisioning is an <strong>explicit</strong> lifecycle step. Authentication, login, dashboard, and role/user listing never create modules, roles, or permissions as a side effect.</p><h2 id="flow" tabindex="-1">Flow <a class="header-anchor" href="#flow" aria-label="Permalink to &quot;Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Admin creates workspace (POST /tenants)  OR  Self-service (POST /public/register-workspace)</span></span>
<span class="line"><span>  → Tenant row + domain</span></span>
<span class="line"><span>  → TenantProvisioningService::provision()</span></span>
<span class="line"><span>       → Initialize billing profile (anchor day, cycle, proration mode, next_billing_at)</span></span>
<span class="line"><span>       → Install every published module where is_default_included = true</span></span>
<span class="line"><span>            (today: Leads, Tasks, Communication Templates)</span></span>
<span class="line"><span>       → TenantAuthorizationProvisioningService::provisionDefaults()</span></span>
<span class="line"><span>            → Ensure shared permission vocabulary from config/tenant-permissions.php</span></span>
<span class="line"><span>            → Create workspace-scoped default roles (superadmin, admin, manager, staff)</span></span>
<span class="line"><span>            → Grant default permission maps (owner receives all)</span></span>
<span class="line"><span>       → Seed module-specific defaults (e.g. lead stages)</span></span>
<span class="line"><span>  → Create workspace owner User (superadmin) via TenantAuthBootstrapService::createOwner()</span></span>
<span class="line"><span>       → Requires roles already provisioned (fails closed if missing)</span></span>
<span class="line"><span>  → (Self-service only) Issue Sanctum tenant-token for SPA login</span></span></code></pre></div><h2 id="separation-of-concerns" tabindex="-1">Separation of concerns <a class="header-anchor" href="#separation-of-concerns" aria-label="Permalink to &quot;Separation of concerns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>TenantProvisioningService</code></td><td>Billing profile, default modules, authorization defaults, module seed data</td></tr><tr><td><code>TenantAuthorizationProvisioningService</code></td><td>Workspace roles + default permission grants (explicit provisioning / maintenance only)</td></tr><tr><td><code>TenantAuthBootstrapService</code></td><td>Create owner user, assign owner role, issue access tokens — <strong>no RBAC mutation</strong></td></tr><tr><td>Data migrations</td><td>Ship new catalog modules and additive permission grants on <code>php artisan migrate</code></td></tr></tbody></table><p>Login, token issuance, dashboard, and role listing <strong>never</strong> provision or repair authorization state.</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><ul><li>No plan assignment.</li><li>Default modules are <code>source=included</code>, <code>is_billable=false</code>, <code>price=0</code>, <code>status=active</code>.</li><li>Workspace owners cannot cancel included modules (<code>POST …/cancel</code> rejected); platform admin may deactivate.</li><li>Missing default modules at provision time fails closed (exception).</li><li>Additional modules are installed later via marketplace (<code>POST /tenants/{tenant}/modules</code>) or admin install; billable modules enter <code>pending</code> until the Billing Engine settles payment.</li><li>Consolidated billing (<code>billing:run-consolidated</code>) picks up billable active subscriptions on <code>next_billing_at</code> — not at provision time for included modules.</li><li>Both Central-admin create and self-service registration require owner credentials and create the owner after provisioning.</li><li>Existing production workspaces receive <strong>new</strong> default-included modules and permissions through <strong>idempotent data migrations</strong>, not seeders and not login-time repair.</li></ul><h2 id="billing-profile-defaults" tabindex="-1">Billing profile defaults <a class="header-anchor" href="#billing-profile-defaults" aria-label="Permalink to &quot;Billing profile defaults&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Initial value</th></tr></thead><tbody><tr><td><code>billing_anchor_day</code></td><td>Today&#39;s day, clamped 1–28</td></tr><tr><td><code>billing_cycle</code></td><td><code>monthly</code></td></tr><tr><td><code>proration_mode</code></td><td>From system setting</td></tr><tr><td><code>next_billing_at</code></td><td>Next month on anchor day</td></tr></tbody></table><p>See <a href="/developer-guide/billing-engine">billing/billing-engine.md</a> for consolidated invoice sequence.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/developer-guide/tenant-rbac">Tenant RBAC</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li><li><a href="/deployment/module-development">Module production registration</a></li><li><a href="/deployment/communication-templates">Communication Templates deployment</a></li></ul>`,14)])])}const g=a(o,[["render",s]]);export{m as __pageData,g as default};
